class Solution:
    def countNumbersWithUniqueDigits(self, n):
        from itertools import permutations
        count = 1
        for length in range(1, n + 1):
            for combo in permutations(range(10), length):
                if length > 1 and combo[0] == 0:
                    continue
                count += 1
        return count

